 */

// Helper function to count how many even numbers in nums[l..r] are less than or equal to 'upper_bound'
long long count_removed_evens(const vector<long long>& nums, int l, int r, long long upper_bound) {
    long long count = 0;
    for (int i = l; i <= r; ++i) {
        if (nums[i] % 2 == 0 && nums[i] <= upper_bound) {
            count++;
        }
    }
    return count;
}


vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
