    for (int i = 0; i < num_queries; ++i) {
        long long l = queries[i][0];
        long long r = queries[i][1];
        long long k = queries[i][2];

        // We are searching for the k-th smallest positive even number, let this number be X.
        // X = 2N. N is the index in the full sequence of evens (1-indexed).

        // The rank of X=2N in the full sequence is N.
        // The count of removed evens <= X is C(X) = count_removed_evens(nums, l, r, X).
        // The rank of X in the remaining sequence is Rank(X) = N - C(X).
        // We seek the smallest X=2N such that Rank(X) >= k.

        // Binary search for N.
        // Lower bound for N: k (since N >= k is required for Rank(X) >= k if C(X) is small)
        long long low_N = 1; 
        // Upper bound for N: k + r - l + 1. Max removed count is r-l+1 <= 10^5. Max k is 10^9.
        // A safe upper bound for N is k + N_max_removed = 10^9 + 10^5.
        long long high_N = k + (r - l + 1) + 1; 

        long long result_N = high_N; // Initialize to a value outside the expected range

        while (low_N <= high_N) {
            long long mid_N = low_N + (high_N - low_N) / 2;
            long long candidate_X = 2 * mid_N;

            // Count how many even numbers <= candidate_X are in nums[l..r]
            long long removed_count = count_removed_evens(nums, l, r, candidate_X);

            // The rank of candidate_X (if it were in the remaining sequence) is mid_N - removed_count.
            long long current_rank = mid_N - removed_count;

            if (current_rank >= k) {
                // This candidate X might be the answer, or we can find a smaller one.
                result_N = mid_N;
                high_N = mid_N - 1;
            } else {
                // The rank is too small, we need a larger X (larger N).
                low_N = mid_N + 1;
            }
        }

        // The smallest N such that Rank(2N) >= k is result_N.
        // The answer is 2 * result_N.
        ans[i] = 2 * result_N;
    }

    return ans;
