        if (nums[i] % 2 == 0 && nums[i] <= X) {
            count++;
        }
    }
    return count;
}

// A more optimized count_removed_even_le using binary search properties for a fixed range [l, r]
// This is still O((r-l+1)) in the worst case if we iterate, but the problem structure suggests
// we need a faster way, likely involving precomputation or binary search on the answer.
