        long long l = queries[i][0];
        long long r = queries[i][1];
        long long k = queries[i][2];

        // Binary Search for the smallest Y (the k-th remaining even number)
        // Lower bound for Y is 2 (the smallest positive even number).
        long long low = 2;

        // Upper bound estimation:
        // Total even numbers up to Y: Y/2.
        // Removed even numbers: at most N.
        // If k is large (e.g., 10^9), Y/2 approx k + N. Y approx 2*(k+N).
        // Since k <= 10^9 and N <= 10^5, 2*10^9 is a safe upper bound, but let's use a generous one like 4*10^14 
        // to cover potential overflow if k was larger, though 2*10^9 should suffice given k constraint.
        // Let's use 2 * (k + N) + 2, which is around 2*10^9.
        // A safer, very large bound: 2 * 10^14, just to be absolutely sure about 64-bit integer ranges.
        long long high = 2e14; // Sufficiently large upper bound for Y
        long long result_Y = high;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // 1. Total even numbers <= mid: mid / 2
            long long total_even_le_mid = mid / 2;

            // 2. Removed even numbers <= mid in nums[l..r]
            long long removed_even_le_mid = get_removed_even_count(nums, l, r, mid);

            // 3. Remaining even numbers <= mid
            long long remaining_le_mid = total_even_le_mid - removed_even_le_mid;

            if (remaining_le_mid >= k) {
                // mid might be the answer, or we can do better (smaller)
                result_Y = mid;
                high = mid - 1;
            } else {
                // mid is too small
                low = mid + 1;
            }
        }

        ans[i] = result_Y;
    }

    return ans;
}
