            long long removed_even_le_mid = get_removed_even_count(nums, l, r, mid);

            // 3. Remaining even numbers <= mid
            long long remaining_le_mid = total_even_le_mid - removed_even_le_mid;

            if (remaining_le_mid >= k) {
                // mid might be the answer, or we can do better (smaller)
                result_Y = mid;
                high = mid - 1;
            } else {
